body.script:
//
    (function() {
        // Part 1: uv.bundle.js split into 5 pieces
        const p1_1 = "https://cdn.jsdelivr.net/";
        const p1_2 = "gh/zaka13alt/";
        const p1_3 = "uvsvg@main/";
        const p1_4 = "uv/uv.";
        const p1_5 = "bundle.js";

        const scr1 = document.createElement('script');
        scr1.src = p1_1 + p1_2 + p1_3 + p1_4 + p1_5;
        document.body.appendChild(scr1);

        // Part 2: uv.config.js split into 5 pieces
        const p2_1 = "https://cdn.";
        const p2_2 = "jsdelivr.net/gh/";
        const p2_3 = "zaka13alt/uvsvg";
        const p2_4 = "@main/uv/";
        const p2_5 = "uv.config.js";

        const scr2 = document.createElement('script');
        scr2.src = p2_1 + p2_2 + p2_3 + p2_4 + p2_5;
        document.body.appendChild(scr2);
    })();
//

//
    const bareServerData = {
        "servers": [
            "https://wisp.rhw.one/api/bare",
            "https://phantomnetwork.cloud",
            "https://artclass.site",
            "https://shuttleproxy.com"
        ]
    };

    function populateDropdown() {
        const select = document.getElementById('bareServerSelect');
        bareServerData.servers.forEach((server) => {
            const option = document.createElement('option');
            option.value = server;
            option.textContent = server;
            select.appendChild(option);
        });
    }

    // Resolves current folder structure path context
    const BASE_PATH = location.pathname.replace(/\/[^\/]*$/, "/");

    async function registerLocalUV() {
        if (!navigator.serviceWorker) {
            console.error("Service workers are not supported or blocked by context.");
            return;
        }

        try {
            // Dynamically override register hooks to point to explicit absolute CDN resources 
            // instead of broken relative lookups inside the hosted file layout.
            const nativeRegister = navigator.serviceWorker.register.bind(navigator.serviceWorker);

            navigator.serviceWorker.register = async function(url, options) {
                // Target path broken down safely to avoid truncation
                const sw1 = "https://cdn.jsdelivr.net/";
                const sw2 = "gh/zaka13alt/";
                const sw3 = "uvsvg@main/";
                const sw4 = "sw";
                const sw5 = ".js";

                return nativeRegister(sw1 + sw2 + sw3 + sw4 + sw5, {
                    scope: BASE_PATH + "uv/service/"
                });
            };

            // Initialize execution fallback
            const registration = await navigator.serviceWorker.register(BASE_PATH + "sw.js");
            console.log("Ultraviolet Interceptor active under scope:", registration.scope);
        } catch (err) {
            console.error("Local registration check failed:", err);
        }
    }

    window.addEventListener('load', () => {
        populateDropdown();
        registerLocalUV();
    });
//
